class Solution {
public:
    int kthSmallest(TreeNode* root, int k) {
        stack<TreeNode *> stack;
        while (root != nullptr || stack.size() > 0) {
            while (root != nullptr) {
                stack.push(root);
                root = root->left;
            }
            root = stack.top();
            stack.pop();
            --k; // 弹栈顺序即中序递增顺序，第 k 次弹出的就是第 k 小
            if (k == 0) {
                break;
            }
            root = root->right;
        }
        return root->val;
    }
};
